            AppLanguage.JAPANESE -> "${minutes / 60}時間${if (minutes % 60 > 0) " ${minutes % 60}分" else ""}"
            AppLanguage.KOREAN -> "${minutes / 60}시간${if (minutes % 60 > 0) " ${minutes % 60}분" else ""}"
